const users = {
  1: { id: 1, name: 'Alice' },
  2: { id: 2, name: 'Bob' },
};

const messages = {
  1: { id: 1, userId: 1, text: 'Hello, Bob!' },
  2: { id: 2, userId: 2, text: 'Hi, Alice!' },
};

function addMessage(state, newMessage) {
  return {
    ...state,
    messages: {
      ...state.messages,
      [newMessage.id]: newMessage
    }
  };
}

const state = { users, messages };

const newMsg = { id: 3, userId: 1, text: 'How are you?' };

const updatedState = addMessage(state, newMsg);

console.log(updatedState.messages[3]);

const EventEmitter = require('events');
const eventBus = new EventEmitter();

// Subscribe to new messages
eventBus.on('newMessage', (message) => {
  console.log('New message received:', message);
});

// When a new message arrives
function receiveNewMessage(message) {
  // Update the state immutably
  state = addMessage(state, message);

  // Emit an event
  eventBus.emit('newMessage', message);
}

receiveNewMessage({ id: 4, userId: 2, text: 'I am good, thanks!' });

