class Box<T> {
  private content: T;
  constructor(content: T) {
    this.content = content;
  }
  getContent(): T {
    return this.content;
  }
}

const box1 = new Box<number>(123);
const box2 = new Box<string>('Hello Box');
console.log(box1.getContent());  // 123
console.log(box2.getContent());  // Hello Box

type ApiResponse<T> = {
  data: T;
  error?: never;
} | {
  data?: never;
  error: string;
};

function handleResponse<T extends ApiResponse<any>>(response: T): ExtractData<T> | null {
  if ('error' in response) {
    console.error('Error:', response.error);
    return null;
  }
  return response.data as ExtractData<T>;
}

