class UpperAttrMetaclass(type):
    # When a new class is created, this method is called
    def __new__(cls, name, bases, dct):
        # Convert all attribute names to uppercase
        uppercase_attrs = {}
        for attr_name, attr_value in dct.items():
            if not attr_name.startswith('__'):
                uppercase_attrs[attr_name.upper()] = attr_value
            else:
                uppercase_attrs[attr_name] = attr_value
        return super().__new__(cls, name, bases, uppercase_attrs)

class SingletonMetaclass(type):
    _instances = {}
    def __call__(cls, *args, **kwargs):
        if cls not in cls._instances:
            cls._instances[cls] = super().__call__(*args, **kwargs)
        return cls._instances[cls]

class Logger(metaclass=SingletonMetaclass):
    def log(self, message):
        print(f"Log: {message}")

logger1 = Logger()
logger2 = Logger()
print(logger1 is logger2)  # True

